#include<bits/stdc++.h>#include<ext/pb_ds/assoc_container.hpp>#include<ext/pb_ds/tree_policy.hpp>using namespace std;using namespace __gnu_pbds; #define ll long long#define nl "\n"#define FASTER ios_base::sync_with_stdio(0); cin.tie(0); cout.tie(0);template <typename T> using ordered_set = tree<T,null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>; const ll N = 1e5+10;const ll mod = 1e9+7;const ll INF = 1e9+10; void solve(){    ll n;    cin>>n;    vector<ll>v(n);    for(int i=0; i<n; i++){        cin>>v[i];    }    vector<ll>a,b;    ll ans = 0;    for(int i=0; i<n; i++){        ll x = a.empty() ? LLONG_MAX : a.back();        ll y = b.empty() ? LLONG_MAX : b.back();        if(x>=v[i] and y>=v[i]){  // can put in both, choose wisely            if(x<=y) a.push_back(v[i]);            else b.push_back(v[i]);        } else if(x>=v[i]) a.push_back(v[i]);        else if(y>=v[i]) b.push_back(v[i]);        else {  // if v[i]>x,y then penalty            ans++;            if(x<=y) a.push_back(v[i]);            else b.push_back(v[i]);        }    }    cout<<ans<<nl;} int main(){    FASTER    ll t;    cin>>t;    while(t--){        solve();    }}                /*Create 2 arrays (a,b). Let, x is the last ele of x & y is the last ele of b. If (x,y>=v[i]) put in bothbut choose wisely & there is no penalty, else (x,y<v[i]) then there is penalty & then put that ele in botharray but choose wisely. */